INSERT IGNORE INTO problems (title, number, difficulty, site, link, description) VALUES ('곱셈', '1629', 'Silver I', 'BOJ', 'https://www.acmicpc.net/problem/1629', '<p>자연수 A를 B번 곱한 수를 알고 싶다. 단 구하려는 수가 매우 커질 수 있으므로 이를 C로 나눈 나머지를 구하는 프로그램을 작성하시오.</p>\n\n### 입력 \n\n <p>첫째 줄에 A, B, C가 빈 칸을 사이에 두고 순서대로 주어진다. A, B, C는 모두 2,147,483,647 이하의 자연수이다.</p>\n\n### 출력 \n\n <p>첫째 줄에 A를 B번 곱한 수를 C로 나눈 나머지를 출력한다.</p>');
INSERT IGNORE INTO problem_categories (problem_id, category_name) SELECT problem_id, '분할 정복을 이용한 거듭제곱' FROM problems WHERE number='1629' AND site='BOJ';
