INSERT IGNORE INTO problems (title, number, difficulty, site, link, description) VALUES ('단어 정렬', '1181', 'Silver V', 'BOJ', 'https://www.acmicpc.net/problem/1181', '<p>알파벳 소문자로 이루어진 N개의 단어가 들어오면 아래와 같은 조건에 따라 정렬하는 프로그램을 작성하시오.</p>\n\n<ol>\n	<li>길이가 짧은 것부터</li>\n	<li>길이가 같으면 사전 순으로</li>\n</ol>\n\n<p>단, 중복된 단어는 하나만 남기고 제거해야 한다.</p>\n\n### 입력 \n\n <p>첫째 줄에 단어의 개수 N이 주어진다. (1 ≤ N ≤ 20,000) 둘째 줄부터 N개의 줄에 걸쳐 알파벳 소문자로 이루어진 단어가 한 줄에 하나씩 주어진다. 주어지는 문자열의 길이는 50을 넘지 않는다.</p>\n\n### 출력 \n\n <p>조건에 따라 정렬하여 단어들을 출력한다.</p>');
INSERT IGNORE INTO problem_categories (problem_id, category_name) SELECT problem_id, '문자열' FROM problems WHERE number='1181' AND site='BOJ';
INSERT IGNORE INTO problem_categories (problem_id, category_name) SELECT problem_id, '정렬' FROM problems WHERE number='1181' AND site='BOJ';
INSERT IGNORE INTO problems (title, number, difficulty, site, link, description) VALUES ('하노이 탑', '1914', 'Silver I', 'BOJ', 'https://www.acmicpc.net/problem/1914', '<p>세 개의 장대가 있고 첫 번째 장대에는 반경이 서로 다른 n개의 원판이 쌓여 있다. 각 원판은 반경이 큰 순서대로 쌓여있다. 이제 수도승들이 다음 규칙에 따라 첫 번째 장대에서 세 번째 장대로 옮기려 한다.</p>\n\n<ol>\n	<li>한 번에 한 개의 원판만을 다른 탑으로 옮길 수 있다.</li>\n	<li>쌓아 놓은 원판은 항상 위의 것이 아래의 것보다 작아야 한다.</li>\n</ol>\n\n<p>이 작업을 수행하는데 필요한 이동 순서를 출력하는 프로그램을 작성하라. 단, 이동 횟수는 최소가 되어야 한다.</p>\n\n<p>아래 그림은 원판이 5개인 경우의 예시이다.</p>\n\n<p style="text-align: center;"><img alt="" src="data:image/png;base64," style="height:200px; width:1050px"></p>\n\n### 입력 \n\n <p>첫째 줄에 첫 번째 장대에 쌓인 원판의 개수 N (1 ≤ N ≤ 100)이 주어진다.</p>\n\n### 출력 \n\n <p>첫째 줄에 옮긴 횟수 K를 출력한다.</p>\n\n<p>N이 20 이하인 입력에 대해서는 두 번째 줄부터 수행 과정을 출력한다. 두 번째 줄부터 K개의 줄에 걸쳐 두 정수 A B를 빈칸을 사이에 두고 출력하는데, 이는 A번째 탑의 가장 위에 있는 원판을 B번째 탑의 가장 위로 옮긴다는 뜻이다. N이 20보다 큰 경우에는 과정은 출력할 필요가 없다.</p>');
INSERT IGNORE INTO problem_categories (problem_id, category_name) SELECT problem_id, '임의 정밀도 / 큰 수 연산' FROM problems WHERE number='1914' AND site='BOJ';
