INSERT IGNORE INTO problems (title, number, difficulty, site, link, description) VALUES ('LIS', '9702', 'Gold Ⅰ', 'BOJ', 'https://www.acmicpc.net/problem/9702', '<p>Mr. C is interested with Longest Increasing Subsequence problem. Given a sequence S = s<sub>1</sub>, s<sub>2</sub>, …, s<sub>N</sub>. The Longest Increasing Subsequence is the subsequence L = l<sub>1</sub>, l<sub>2</sub>, …, l<sub>k</sub> of S such that l<sub>1</sub> &lt; l<sub>2</sub> &lt; … &lt; l<sub>k</sub>.&nbsp;</p>\n\n<p>Given a sequence S, find the total length of LIS of every consecutive subsequence (subsequence which elements are consecutive in the original sequence) of S with non zero length!</p>\n\n### 입력 \n\n\n<p>The first line of input consists of an integer T denotes the number of cases. It is followed by T blocks, each representing a case.</p>\n\n<p>The first line of each case contains an integers: N (1 ≤ N ≤ 500), the length of S.</p>\n\n<p>The next N lines each consists of an integer s<sub>i</sub> (1 ≤ s<sub>i</sub> ≤ N) denoting the i-th element of S. Each element of S is unique.</p>\n\n### 출력 \n\n\n<p>Output consists of T lines, each describes the solution for each case with the same order as in input.</p>\n\n<p>Each case consists of a single line with the format “Case #i: S”, where i represents the case number and S represents the total length of LIS of every consecutive subsequence of S.</p>');
INSERT IGNORE INTO problem_categories (problem_id, category_name) SELECT problem_id, '* 가장 긴 증가하는 부분 수열: o(n log n)' FROM problems WHERE number='9702' AND site='BOJ';
INSERT IGNORE INTO problems (title, number, difficulty, site, link, description) VALUES ('경찰차', '2618', 'Platinum IV', 'BOJ', 'https://www.acmicpc.net/problem/2618', '<p>어떤 도시의 중심가는 N개의 동서방향 도로와 N개의 남북방향 도로로 구성되어 있다.</p>\n\n<p>모든 도로에는 도로 번호가 있으며 남북방향 도로는 왼쪽부터 1에서 시작하여 N까지 번호가 할당되어 있고 동서방향 도로는 위부터 1에서 시작하여 N까지 번호가 할당되어 있다. 또한 동서방향 도로 사이의 거리와 남 북방향 도로 사이의 거리는 모두 1이다. 동서방향 도로와 남북방향 도로가 교차하는 교차로의 위치는 두 도로의 번호의 쌍인 (동서방향 도로 번호, 남북방향 도로 번호)로 나타낸다. N이 6인 경우의 예를 들면 다음과 같다.</p>\n\n<p style="text-align: center;"><img alt="" src="" style="width: 207px; height: 170px;"></p>\n\n<p>이 도시에는 두 대의 경찰차가 있으며 두 차를 경찰차1과 경찰차2로 부른다. 처음에는 항상 경찰차1은 (1, 1)의 위치에 있고 경찰차2는 (N, N)의 위치에 있다. 경찰 본부에서는 처리할 사건이 있으면 그 사건이 발생된 위치를 두 대의 경찰차 중 하나에 알려 주고, 연락 받은 경찰차는 그 위치로 가장 빠른 길을 통해 이동하여 사건을 처리한다. (하나의 사건은 한 대의 경찰차가 처리한다.) 그리고 사건을 처리 한 경찰차는 경찰 본부로부터 다음 연락이 올 때까지 처리한 사건이 발생한 위치에서 기다린다. 경찰 본부에서는 사건이 발생한 순서대로 두 대의 경찰차에 맡기려고 한다. 처리해야 될 사건들은 항상 교차로에서 발생하며 경찰 본부에서는 이러한 사건들을 나누어 두 대의 경찰차에 맡기되, 두 대의 경찰차들이 이동하는 거리의 합을 최소화 하도록 사건을 맡기려고 한다.</p>\n\n<p>예를 들어 앞의 그림처럼 N=6인 경우, 처리해야 하는 사건들이 3개 있고 그 사건들이 발생된 위치 를 순서대로 (3, 5), (5, 5), (2, 3)이라고 하자. (3, 5)의 사건을 경찰차2에 맡기고 (5, 5)의 사건도 경찰차2에 맡기며, (2, 3)의 사건을 경찰차1에 맡기면 두 차가 이동한 거리의 합은 4 + 2 + 3 = 9가 되 고, 더 이상 줄일 수는 없다.</p>\n\n<p>처리해야 할 사건들이 순서대로 주어질 때, 두 대의 경찰차가 이동하는 거리의 합을 최소화 하도록 사건들을 맡기는 프로그램을 작성하시오.</p>\n\n### 입력 \n\n <p>첫째 줄에는 동서방향 도로의 개수를 나타내는 정수 N(5 ≤ N ≤ 1,000)이 주어진다. 둘째 줄에는 처리해야 하는 사건의 개수를 나타내는 정수 W(1 ≤ W ≤ 1,000)가 주어진다. 셋째 줄부터 (W+2)번째 줄까지 사건이 발생된 위치가 한 줄에 하나씩 주어진다. 경찰차들은 이 사건들을 주어진 순서대로 처리해야 한다. 각 위치는 동서방향 도로 번호를 나타내는 정수와 남북방향 도로 번호를 나타내는 정수로 주어지며 두 정수 사이에는 빈칸이 하나 있다. 두 사건이 발생한 위치가 같을 수 있다.</p>\n\n### 출력 \n\n <p>첫째 줄에 두 경찰차가 이동한 총 거리를 출력한다. 둘째 줄부터 시작하여 (i+1)번째 줄에 i(1 ≤ i ≤ W)번째 사건이 맡겨진 경찰차 번호 1 또는 2를 출력한다.</p>');
INSERT IGNORE INTO problem_categories (problem_id, category_name) SELECT problem_id, '다이나믹 프로그래밍' FROM problems WHERE number='2618' AND site='BOJ';
INSERT IGNORE INTO problems (title, number, difficulty, site, link, description) VALUES ('전설', '19585', 'Platinum III', 'BOJ', 'https://www.acmicpc.net/problem/19585', '<p>Sogang ICPC Team에는 색상 이름과 닉네임의 순서로 이여서 팀명을 지으면 ICPC 리저널에서 수상할 수 있다는 전설이 있다. 색상 이름들과 닉네임들이 주어질 때, <em>Q</em>개의 팀에 대해 다음 리저널에서 수상할 수 있을지 전설에 기반해 알려주는 프로그램을 작성하자.</p>\n\n### 입력 \n\n <p>첫째 줄에는 색상의 종류 <em>C</em>와 닉네임의 개수 <em>N</em>이 주어진다. (1 ≤ <em>C</em>, <em>N</em> ≤ 4,000)</p>\n\n<p>다음 <em>C</em>개의 줄에는 색상 이름 <em>C</em>개가 한 줄에 하나씩 주어진다. 색상 이름은 중복되지 않는다.</p>\n\n<p>다음 <em>N</em>개의 줄에는 Sogang ICPC Team 구성원들의 닉네임 <em>N</em>개가 한 줄에 하나씩 주어진다. 닉네임도 중복되지 않는다.</p>\n\n<p>다음 줄에는 팀의 개수 <em>Q</em>가 주어진다. (1 ≤ <em>Q</em> ≤ 20,000)</p>\n\n<p>다음 <em>Q</em>개의 줄에는 팀명 <em>Q</em>개가 한 줄에 하나씩 주어진다. 팀명은 중복되지 않는다.</p>\n\n<p>모든 색상 이름의 길이와 닉네임의 길이는 1,000글자를 넘지 않는다. 모든 팀명은 2,000글자를 넘지 않는다. 모든 문자열은 알파벳 소문자로만 이루어져 있다.</p>\n\n### 출력 \n\n <p>팀명이 입력된 순서대로, 전설에 따라 해당 팀이 다음 리저널에서 수상할 수 있다면 <tt><span style="background-color:#dddddd;">Yes</span></tt>, 아니라면 <tt><span style="background-color:#dddddd;">No</span></tt>를 출력한다.</p>');
